esqlQuery.esql:
FROM logs-azure.activity.otel-*
// Restrict to Azure Activity Logs (Administrative category)
| WHERE azure.category IS NOT NULL
| WHERE azure.category == "Administrative"
// Capture both Failure and Failed result types (Azure uses inconsistent casing)
| WHERE azure.result.type IN ("Failure", "Failed")
// Derive caller for grouping (user.id or principal ID)
| EVAL caller = COALESCE(user.id, azure.identity.authorization.evidence.principal.id, "unknown")
// Aggregate by operation and caller for context; adjust minimum count to reduce noise
| STATS failed_count = COUNT(*), sample_timestamps = VALUES(@timestamp) BY azure.operation.name, caller, network.peer.address
// Minimum failures to alert — tune based on environment noise
| WHERE failed_count >= 3
| SORT failed_count DESC
| LIMIT 20
